import React, {useState, useEffect} from 'react'
import styled from 'styled-components'
import google from './static/googleIcon.jpg'
import facebook from './static/facebook.jpg'
import cancel from './static/x-circle.svg'
import {useSelector, useDispatch} from 'react-redux'
import {accountSelector, openLoginForm, switchLoginToRegister, handleLogin, handleLogout} from '../redux/accountSlice'
import {registerUser, loginUser} from '../WebAPI'

const Form = styled.form `
position:fixed;
display:flex;
width:30vw;
height:${props => props.opened ? '80vh' : '0'};
border-radius:8px;
background-color:white;
margin:auto;
top:0;
bottom:0;
left:0;
right:0;
z-index:2;
flex-direction:column;
justify-content:space-evenly;
align-items:center;
padding:${props => props.opened ? '30px 60px' : '0'};
box-sizing:border-box;
transition:opacity 0.3s ease-in-out;
overflow:hidden;
opacity:${props => props.opened ? '1' : '0'};
`

const Wrapper = styled.div `
font-size:1rem;
width:100%;
display:flex;
justify-content:center;
align-items:center;
`

const SignIn = styled.div `
font-weight:${props => props.selected ? 'normal' : '800'};
&:hover {
	cursor:pointer;
}
`

const Register = styled.div `
font-weight:${props => props.selected ? '800' : 'normal'};
margin-left:20px;
&:hover {
	cursor:pointer;
}
`

const Username = styled.div `
width:100%;
`

const UsernameInput = styled.input `
height:35px;
width:100%;
`

const Email = styled.div `
width:100%;
`

const EmailInput = styled.input `
height:35px;
width:100%;
`

const Password = styled.div `
width:100%;
`

const PasswordInput = styled.input `
height:35px;
width:100%;
`

const SignInSubmit = styled.input `
width:100%;
height:40px;
color:white;
font-weight:bold;
font-size:1.1rem;
background-color:#1C1C1C;
border:1px solid #1C1C1C;
border-radius:8px;
`

const RegisterSubmit = styled.input `
width:100%;
height:40px;
color:white;
font-weight:bold;
font-size:1.1rem;
background-color:#1C1C1C;
border:1px solid #1C1C1C;
border-radius:8px;
`

const OR = styled.div ``

const GoogleSignIn = styled.div `
width:100%;
height:40px;
font-weight:bold;
font-size:1rem;
border:1px solid #1C1C1C;
border-radius:8px;
display:flex;
align-items:center;

`

const FaceBookSignIn = styled.div `
width:100%;
height:40px;
font-weight:bold;
font-size:1rem;
border:1px solid #1C1C1C;
border-radius:8px;
display:flex;
align-items:center;
`

const GoogleIcon = styled.div `
position:absolute;
background-image:url(${google});
width:20px;
height:20px;
background-size:cover;
background-position:center;
margin-left:10px;
`

const FaceBookIcon = styled.div `
position:absolute;
background-image:url(${facebook});
width:20px;
height:20px;
background-size:cover;
background-position:center;
margin-left:10px;
`

const Div = styled.div `
margin:0 auto;
`

const Name = styled.div `
font-size:0.8rem;
margin-bottom:5px;
color:grey;
`

const Cancel = styled.div `
background-image:url(${cancel});
background-position:center;
background-size:cover;
width:18px;
height:18px;
position:absolute;
top:12px;
right:12px;
&:hover {
	cursor:pointer;
}
`

const TermsAndConditions = styled.div `
white-space:pre-wrap;
word-break:break-all;
font-size:0.8rem;
color:rgba(0, 0, 0, 0.7);
`

const WrapperforInputs = styled.div `
height:80%;
width:100%;
display:flex;
justify-content:space-between;
flex-direction:column;
align-items:center;
`

const Warning = styled.div `
font-size:0.8rem;
color:#DB4D6D;
text-align:center;
width:100%;
height:15px;
line-height:15px;
`

const onSuccess = (res) => {
	console.log('success:', res);
}

const onFailure = (err) => {
	console.log('failed:', err);
};

export default function AccountForm () {
	const account = useSelector(accountSelector)
	const dispatch = useDispatch()
	const [registerUsername, setRegisterUsername] = useState('')
	const [registerEmail, setRegisterEmail] = useState('')
	const [registerPassword, setRegisterPassword] = useState('')
	const [loginUsername, setLoginUsername] = useState('')
	const [loginPassword, setLoginPassword] = useState('')
	const [warning, setWarning] = useState('')





	const onCancelLoginForm = () => {
		dispatch(openLoginForm())
	}

	const onToggleSignIn = () => {
		dispatch(switchLoginToRegister())
	}

	const onToggleRegister = () => {
		dispatch(switchLoginToRegister())
	}

	const onRegisterUsernameChange = e => {
		setRegisterUsername(e.target.value)
	}

	const onRegisterEmailChange = e => {
		setRegisterEmail(e.target.value)
	}

	const onRegisterPasswordChange = e => {
		setRegisterPassword(e.target.value)
	}

	const onLoginUsernameChange = e => {
		setLoginUsername(e.target.value)
	}

	const onLoginPasswordChange = e => {
		setLoginPassword(e.target.value)
	}

	const onSubmit = e => {
		e.preventDefault()

		if (account.isRegisterActive === true) {
			if (registerUsername !== '' && registerEmail !== '' && registerPassword !== '') {
				const data = {
					username:registerUsername,
					email:registerEmail,
					password:registerPassword
				}
				registerUser(data)
			} else {
				setWarning('Missing Info')
			}

		} else {
			if (loginUsername !== '' && loginPassword !== '') {
				const data = {
					username:loginUsername,
					password:loginPassword
				}
				loginUser(data)
				dispatch(handleLogin())
			} else {
				setWarning('Missing Info')
			}
		}
		dispatch(openLoginForm())
	}

	return (
		<>
		<Form opened={account.isLoginFormOpen} onSubmit={onSubmit}>
			<Cancel onClick={onCancelLoginForm}/>
			<Wrapper>
				<SignIn onClick={onToggleSignIn} selected={account.isRegisterActive}>SIGN IN</SignIn>
				<Register onClick={onToggleRegister} selected={account.isRegisterActive}>REGISTER</Register>
			</Wrapper>
			<Warning>{warning}</Warning>
			{account.isRegisterActive ? 

			<WrapperforInputs>
				<Username>
					<label>
						<Name>USERNAME</Name>
						<UsernameInput value={registerUsername} onChange={onRegisterUsernameChange}/>
					</label>
				</Username>
				<Email>
					<label>
						<Name>EMAIL</Name>
						<EmailInput value={registerEmail} onChange={onRegisterEmailChange}/>
					</label>
				</Email>
				<Password>
					<label>
						<Name>PASSWORD</Name>
						<PasswordInput value={registerPassword} onChange={onRegisterPasswordChange}/>
					</label>
				</Password>
				<TermsAndConditions>By registering, you agree with our Terms & Conditions and Privacy and Cookie Policy.</TermsAndConditions>
				<RegisterSubmit type='submit' value='Register'></RegisterSubmit>
			</WrapperforInputs>

			: 
			<WrapperforInputs>
				<Email>
					<label>
						<Name>USERNAME</Name>
						<UsernameInput value={loginUsername} onChange={onLoginUsernameChange}/>
					</label>
				</Email>
				<Password>
					<label>
						<Name>PASSWORD</Name>
						<PasswordInput value={loginPassword} onChange={onLoginPasswordChange}/>
					</label>
				</Password>
				<SignInSubmit type='submit' value='Sign In'></SignInSubmit>
				<OR>OR</OR>
				<FaceBookSignIn>
					<FaceBookIcon></FaceBookIcon>
					<Div>Continue with FaceBook</Div>
				</FaceBookSignIn>
			</WrapperforInputs>
			}
		</Form>
		</>

	)
}



/*
<GoogleSignIn>
					<GoogleIcon></GoogleIcon>
					<Div>Continue with Google</Div>
				</GoogleSignIn>
*/
